// Safely extract and validate inbound webhook payload
const body = $json.body || $json || {};
const problemId = body.problem_id;
const traceId = body.trace_id || `prb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
const runId = $execution?.id ? String($execution.id) : `manual-${Date.now()}`;

if (!problemId) {
  return [{ json: { route: 'error', stage: 'validate_inbound', error: 'missing_problem_id', trace_id: traceId, run_id: runId, raw: body } }];
}

return [{
  json: {
    route: 'ok',
    stage: 'validate_inbound',
    trace_id: traceId,
    run_id: runId,
    problem_id: String(problemId),
    title: body.title || 'Unknown Problem',
    priority: body.priority || body.severity || 'high',
    affected_tickets_count: body.affected_tickets_count || 0
  }
}];

// Merge inbound context with enriched backend data
// Problem model has no dedicated description field

const ctx = $node['Store Inbound Context'].json;
const detail = $json || {};

if (detail.error || detail.statusCode >= 400) {
  return [{ json: { route: 'error', stage: 'fetch_problem', trace_id: ctx.trace_id, run_id: ctx.run_id, error: detail.error || 'backend_fetch_failed', status: detail.statusCode } }];
}

const problemId = ctx.problem_id;
const uiBase = $env.FRONTEND_BASE_URL || 'http://localhost:3000';

return [{
  json: {
    route: 'ok',
    stage: 'merge_enriched',
    trace_id: ctx.trace_id,
    run_id: ctx.run_id,
    problem_id: problemId,
    title: detail.title || ctx.inbound_title || 'Problem Detected',
    priority: detail.priority || ctx.inbound_priority || detail.severity || 'high',
    status: detail.status || 'open',
    affected_tickets_count: detail.affected_tickets_count ?? ctx.inbound_affected_count ?? 0,
    root_cause: detail.root_cause || 'Under investigation',
    workaround: detail.workaround || 'None yet',
    permanent_fix: detail.permanent_fix || 'None yet',
    created_at: detail.created_at || new Date().toISOString(),
    problem_url: `${uiBase}/problems/${problemId}`,
    raw_detail: detail
  }
}];

const d = $json;
const rawPriority = d.priority || d.raw_detail?.priority || d.inbound_priority || d.raw_detail?.severity || 'high';
const pri = String(rawPriority).trim() || 'high';
const tickets = Array.isArray(d.raw_detail?.tickets) ? d.raw_detail.tickets : [];
const topTickets = tickets.slice(0, 3).map(t => t.title).filter(Boolean);

const summaryBits = [];
summaryBits.push(`${d.title || 'Problem detected'} is currently ${d.status || 'open'}.`);
summaryBits.push(`Impact priority is ${pri.toUpperCase()} with ${d.affected_tickets_count ?? tickets.length ?? 0} related ticket(s).`);
if (topTickets.length) summaryBits.push(`Representative impacted tickets include: ${topTickets.join('; ')}.`);
summaryBits.push(d.root_cause && d.root_cause !== 'Under investigation' ? `Likely root cause: ${d.root_cause}.` : 'Root cause is still under investigation.');
if (d.workaround && d.workaround !== 'None yet.') summaryBits.push(`Current workaround: ${d.workaround}.`);
if (d.permanent_fix && d.permanent_fix !== 'None yet.') summaryBits.push(`Planned permanent fix: ${d.permanent_fix}.`);

const generatedSummary = summaryBits.join(' ');
const subject = `[ITSM Problem] ${pri.toUpperCase()} - ${d.title || 'Problem Detected'}`;
const body = `Problem ${d.problem_id || 'N/A'} has been flagged for response. The issue titled "${d.title || 'N/A'}" is currently "${d.status || 'open'}" with priority "${pri.toUpperCase()}" and currently affects ${d.affected_tickets_count ?? 0} ticket(s). Detailed summary: ${generatedSummary} Detection time: ${d.created_at || new Date().toISOString()}. Open the problem record here: ${d.problem_url || 'N/A'}. Trace reference: ${d.trace_id || 'N/A'}; workflow run: ${d.run_id || 'N/A'}. Source: system:n8n.`;

return [{ json: { ...d, stage: 'build_email', priority: pri, email_subject: subject, email_body: body, generated_summary: generatedSummary } }];

const payload = {
  workflow: 'Problem Launch Notifier',
  timestamp: new Date().toISOString(),
  stage: $json.stage || 'unknown',
  trace_id: $json.trace_id || 'N/A',
  run_id: $json.run_id || 'N/A',
  route: 'error',
  error: $json.error || $json.message || JSON.stringify($json)
};
console.error('[n8n][problem-notifier][error]', JSON.stringify(payload));
return [{ json: payload }];

const payload = {
  workflow: 'Problem Launch Notifier',
  timestamp: new Date().toISOString(),
  stage: 'email_sent',
  route: 'ok',
  trace_id: $json.trace_id || 'N/A',
  run_id: $json.run_id || 'N/A',
  problem_id: $json.problem_id || 'N/A',
  email_to: $env.PROBLEM_ALERT_EMAIL_TO || 'N/A',
  message_id: $json.messageId || null
};
console.log('[n8n][problem-notifier][success]', JSON.stringify(payload));
return [{ json: payload }];
